package concrete.goonie.chart.api.indicator; import concrete.goonie.chart.api.data.*; import concrete.goonie.chart.api.model.Timeframe; import concrete.goonie.chart.internal.render.Style; import java.util.Arrays; public final class IndicatorBuffer { private final String name; private final IndicatorBufferRenderType renderType; private final double[] values; private final Style style; private double emptyValue=Double.NaN, histogramBaseValue=0.0; private double[] secondaryValues; private String[] textValues; public IndicatorBuffer(String name, IndicatorBufferRenderType renderType, int size, Style style){ this.name=name; this.renderType=renderType; this.values=new double[size]; this.style=style; Arrays.fill(values,Double.NaN);} public String getName(){return name;} public IndicatorBufferRenderType getRenderType(){return renderType;} public Style getStyle(){return style;} public double[] getValues(){return values;} public double getEmptyValue(){return emptyValue;} public void setEmptyValue(double emptyValue){this.emptyValue=emptyValue;} public double getHistogramBaseValue(){return histogramBaseValue;} public void setHistogramBaseValue(double histogramBaseValue){this.histogramBaseValue=histogramBaseValue;} public void clear(){ Arrays.fill(values,emptyValue); if(secondaryValues!=null) Arrays.fill(secondaryValues,emptyValue); if(textValues!=null) Arrays.fill(textValues,null);} public void set(int index, double value){ values[index]=value; } public void setSecondary(int index, double value){ if(secondaryValues==null){ secondaryValues=new double[values.length]; Arrays.fill(secondaryValues,Double.NaN);} secondaryValues[index]=value;} public void setText(int index, String text){ if(textValues==null) textValues=new String[values.length]; textValues[index]=text; } public DataSet toDataSet(String prefix, Timeframe... timeframes){ int n=0; for(double v:values) if(!Double.isNaN(v)) n++; double[] x=new double[n], y=new double[n], s=secondaryValues==null?null:new double[n]; String[] tx=textValues==null?null:new String[n]; int j=0; for(int i = 0; i<values.length; i++){ if(Double.isNaN(values[i])) continue; x[j]=i; y[j]=values[i]; if(s!=null) s[j]=secondaryValues[i]; if(tx!=null) tx[j]=textValues[i]; j++; } if(renderType==IndicatorBufferRenderType.HISTOGRAM){ BarDataSet d=new BarDataSet(prefix+" - "+name,x,y,histogramBaseValue,timeframes); d.setBarStyle(style); return d; } if(renderType==IndicatorBufferRenderType.TEXT){ TextDataSet d=new TextDataSet(prefix+" - "+name,x,y,tx==null?new String[n]:tx,timeframes); d.setTextStyle(style); return d; } if(renderType==IndicatorBufferRenderType.RECT){ double[] top=new double[n], bottom=new double[n]; String[] labels=tx==null?new String[n]:tx; for(int i = 0; i<n; i++){ top[i]=Math.max(y[i], s!=null?s[i]:y[i]); bottom[i]=Math.min(y[i], s!=null?s[i]:y[i]); } RectDataSet d=new RectDataSet(prefix+" - "+name,x,top,x,bottom,labels,timeframes); d.setRectStyle(style); d.setBorderStyle(style.copy().withCornerRadius(style.cornerRadius>0f?style.cornerRadius:8f)); return d; } LineDataSet d=new LineDataSet(prefix+" - "+name,x,y,timeframes); d.setLineStyle(style.copy()); return d; } }